<?php

namespace Tests\Integration;

use Tests\TestCase;
use App\Services\S3StorageService;
use Illuminate\Support\Facades\Config;
use Illuminate\Support\Facades\Log;

class S3StorageIntegrationTest extends TestCase
{
    protected string $image;
    protected S3StorageService $service;

    protected function setUp(): void
    {
        parent::setUp();

        // 🔥 pakai S3 asli
        Config::set('filesystems.default', 's3');

        $this->service = new S3StorageService();

        $this->image = "data:image/jpeg;base64,";
    }

    public function test_upload_to_real_s3_should_return_path()
    {
        $path = $this->service->uploadBase64(
            $this->image,
            'integration-test',
            'image'
        );

        Log::info("S3 Path: " . $path);

        $this->assertNotNull($path);
        $this->assertStringContainsString('integration-test/', $path);
        $this->assertStringEndsWith('.jpg', $path);
    }

    public function test_generate_temporary_url_from_real_s3()
    {
        $path = $this->service->uploadBase64(
            $this->image,
            'integration-test',
            'image'
        );

        $url = $this->service->getTemporaryUrl($path);

        Log::info("Temporary URL: " . $url);

        $this->assertNotNull($url);
        $this->assertStringContainsString('http', $url);
        $this->assertStringContainsString('X-Amz', $url); // 🔥 signed URL
    }

    public function test_invalid_base64_should_fail()
    {
        $this->expectException(\Exception::class);

        $this->service->uploadBase64(
            'invalid-base64',
            'integration-test',
            'image'
        );
    }

    public function test_file_not_found_should_fail_when_generate_url()
    {
        $this->expectException(\Exception::class);

        $this->service->getTemporaryUrl(
            'integration-test/not-found.jpg'
        );
    }
}